// Script Continued Below
// KT - REQUEST TYPE
function onSubmit() {

	var table = 'x_153465_discovert_tasker_requests';
	var RequestSysId; 
	var modalForm;
	var formAction = g_form.getActionName();

	// STRY0088787 added if statement to check the submit is a Request submit, then doin save before continuing
	if((formAction == 'openModalRespondClarificationSP')
		|| (formAction == 'openModalRequestClarificationSP')
		|| (formAction == 'openModalRespondExtensionSP')
		|| (formAction == 'openModalRequestExtensionSP')
		|| (formAction == 'openModalRespondReassignmentSP')
		|| (formAction == 'openModalRequestReassignmentSP')
		){
		// If the form is dirty, ask the user if they would like to save the record
		var saveChangeConfirmation = false;
		var saveMsg = getMessage('Tasker - Modal Save Changes Message');
		if(typeof spModal != 'undefined'){
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				var fMsg = changeFieldList.join(', ');					
				saveMsg += "  " + fMsg;
				saveChangeConfirmation = true;
			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			saveMsg += JSON.stringify(g_form.modifiedFields);
			saveChangeConfirmation = true;
		}

		// use the variable set above here to show confirmation message.
		if(saveChangeConfirmation){				
			if(confirm(saveMsg)){
				g_form.save();
			} else{
				return false;
			}
		}
	}

	//----------------------------------------------------------------------------------------------------------
	if(formAction == 'openModalRespondClarificationSP'){
		getRequestSysId('Clarification');
		if (typeof spModal != 'undefined' ) { 
			setTimeout(function(){

				spModal.open({
				title:  getMessage('Tasker - Title - Respond Clarification Request'),
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: RequestSysId, view:'responsetop', isModal: true},
					size:'lg',
					buttons: []
				});

			}, 2000);
		} else {
			modalForm = new GlideModalForm(getMessage('Tasker - Title - Respond Clarification Request'), table);
			modalForm.addParm('sysparm_view', 'responsetop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(RequestSysId);
		}
		return false;
	}

	if(formAction == 'openModalRequestClarificationSP'){
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: getMessage('Tasker - Title - Request Clarification'),
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: -1, view: 'requesttop', parent:g_form.getUniqueValue(), u_request_type: 'Clarification', isModal: true},
					size:'lg',
					buttons: []
				});
		} else{
			modalForm = new GlideModalForm(getMessage('Tasker - Title - Request Clarification'), table);
			modalForm.addParm('sysparm_query','parent='+g_form.getUniqueValue() + '^u_request_type=' + 'Clarification');
			modalForm.addParm('sysparm_view', 'requesttop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;

	}


	//----------------------------------------------------------------------------------------------------------
	if(formAction == 'openModalRespondExtensionSP'){
		getRequestSysId('Extension');
		if (typeof spModal != 'undefined' ) { 
			setTimeout(function(){
				spModal.open({
				title: getMessage('Tasker - Title - Respond Extension Request'),
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: RequestSysId, view:'responsetop', isModal: true},
					size:'lg',
					buttons: []
				});

			}, 2000);
		} else {
			modalForm = new GlideModalForm(getMessage('Tasker - Title - Respond Extension Request'), table);
			modalForm.addParm('sysparm_view', 'responsetop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(RequestSysId);
		}
		return false;
	}

	if(formAction == 'openModalRequestExtensionSP'){
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: getMessage('Tasker - Title - Request Extension'), 
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: -1, view: 'requesttop', parent:g_form.getUniqueValue(), u_request_type: 'Extension', isModal: true},
					size:'lg',
					buttons: []
			});
		} else{
			modalForm = new GlideModalForm(getMessage('Tasker - Title - Request Extension'), table);
			modalForm.addParm('sysparm_query','parent='+g_form.getUniqueValue() + '^u_request_type=' + 'Extension');
			modalForm.addParm('sysparm_view', 'requesttop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;
	}

	//----------------------------------------------------------------------------------------------------------
	if(formAction == 'openModalRespondReassignmentSP'){
		getRequestSysId('Reassignment');
		if (typeof spModal != 'undefined' ) { 
			setTimeout(function(){

				spModal.open({
				title: getMessage('Tasker - Title - Respond Reassignment Request'),
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: RequestSysId, view:'responsetop', isModal: true},
					size:'lg',
					buttons: []
				});

			}, 2000);
		} else {
			modalForm = new GlideModalForm(getMessage('Tasker - Title - Respond Reassignment Request'), table);
			modalForm.addParm('sysparm_view', 'responsetop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(RequestSysId);
		}
		return false;
	}

	if(formAction == 'openModalRequestReassignmentSP'){
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: getMessage('Tasker - Title - Request Reassignment'),
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: table, sys_id: -1, view: 'requesttop', isModal: true, parent:g_form.getUniqueValue(), u_request_type: 'Reassignment'},
					size:'lg',
					buttons: []
				});
		} else{
			modalForm = new GlideModalForm(getMessage('Tasker - Title - Request Reassignment'), table);
			modalForm.addParm('sysparm_query','parent='+g_form.getUniqueValue() + '^u_request_type=' + 'Reassignment');
			modalForm.addParm('sysparm_view', 'requesttop'); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;
	}

	//-----------------------------------------------------------------------------------------------------------------	
	function getRequestSysId(SelectedRequestType){
			var ga = new GlideAjax("ClientTaskRequest");
			ga.addParam('sysparm_name', 'getRequestIdToOpen');
			ga.addParam('pTaskSysId', g_form.getUniqueValue());
			ga.addParam('pRequestType', SelectedRequestType);
			ga.addParam('pStatus', 'In Progress');

			ga.getXML(getRequestSysId, null);

			function getRequestSysId(response){
				var answer = response.responseXML.documentElement.getAttribute("answer");
				RequestSysId = answer;			
			}
	}
}
